const body = $input.first().json.body;

const orderId = body.order_id || '';
const statusCode = body.status_code || '';
const grossAmount = body.gross_amount || '';
const transactionStatus = body.transaction_status || '';
const paymentType = body.payment_type || '';
const fraudStatus = body.fraud_status || '';
const transactionId = body.transaction_id || '';
const transactionTime = body.transaction_time || '';
const signatureKey = body.signature_key || '';
const subscriptionId = body.subscription_id || null;
const savedTokenId = body.saved_token_id || null;

const serverKey = $env.MIDTRANS_SERVER_KEY;
const crypto = require('crypto');
const expectedSignature = crypto.createHash('sha512')
  .update(orderId + statusCode + grossAmount + serverKey)
  .digest('hex');

const isValid = signatureKey === expectedSignature;

let newStatus = 'pending';
if (transactionStatus === 'capture' || transactionStatus === 'settlement') {
  if (fraudStatus === 'accept' || fraudStatus === '') {
    newStatus = 'paid';
  }
} else if (transactionStatus === 'cancel' || transactionStatus === 'deny') {
  newStatus = 'failed';
} else if (transactionStatus === 'expire') {
  newStatus = 'expired';
} else if (transactionStatus === 'pending') {
  newStatus = 'pending';
} else if (transactionStatus === 'refund') {
  newStatus = 'refunded';
}

const now = new Date();
const nextDueDate = new Date(now.getFullYear(), now.getMonth() + 1, now.getDate());
const nextDueDateStr = nextDueDate.toISOString().split('T')[0];

return {
  json: {
    isValid,
    orderId,
    transactionId,
    transactionStatus,
    paymentType,
    fraudStatus,
    newStatus,
    grossAmount,
    transactionTime,
    subscriptionId,
    savedTokenId,
    nextDueDateStr,
    isSubscription: !!subscriptionId
  }
};
